import { UserModel as User, IUser, UserRole } from '../../infrastructure/database/models/user.model';
import bcrypt from 'bcrypt';

export class UserService {
  /**
   * Find a user by phone or identity card
   */
  async findExistingUser(phone: string, identityCard: string): Promise<IUser | null> {
    return await User.findOne({ 
      $or: [{ phone }, { identity_card: identityCard }] 
    }).exec();
  }

  /**
   * Create a new student user with hashed password
   */
  async createStudentUser(userData: Partial<IUser>): Promise<IUser> {
    const { 
      first_name, last_name, username, email, phone, 
      identity_card, dob, address, password,
      existing_license_num, existing_license_rank
    } = userData;

    // Helper to remove Vietnamese accents for clean email/username
    const removeAccents = (str: string) => {
      return str.normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/đ/g, 'd')
        .replace(/Đ/g, 'D');
    };

    const first = first_name || '';
    const last = last_name || '';

    // Auto-generate email: lastname + first name initials + @ahvholding.com
    // E.g. Nguyễn Văn A -> nguyenva@ahvholding.com
    const normalizedLast = removeAccents(last.toLowerCase().replace(/\s+/g, ''));
    const initials = first.split(' ').filter(Boolean).map(word => removeAccents(word.charAt(0).toLowerCase())).join('');

    let baseUsername = `${normalizedLast}${initials}`;
    let generatedEmail = email || `${baseUsername}@ahvholding.com`;

    // If email is auto-generated, ensure it and the username are unique
    if (!email) {
      const existingUser = await User.findOne({ 
        $or: [ { email: generatedEmail }, { username: baseUsername } ] 
      }).select('_id').lean().exec();

      if (existingUser) {
        const timestamp = Date.now().toString().slice(-4); // Last 4 digits of ms
        baseUsername = `${baseUsername}${timestamp}`;
        generatedEmail = `${baseUsername}@ahvholding.com`;
      }
    }

    const defaultPassword = 'Password@123';
    const hashedPassword = await bcrypt.hash(password || defaultPassword, 10);

    return await User.create({
      first_name: first,
      last_name: last,
      username: username || generatedEmail.split('@')[0],
      email: generatedEmail,
      phone,
      identity_card: identity_card || 'Chưa cập nhật',
      dob: dob ? new Date(dob) : undefined,
      address: address || 'Chưa cập nhật',
      password: hashedPassword,
      role: UserRole.Student,
      existing_license_num: (existing_license_num as any) || null,
      existing_license_rank: (existing_license_rank as any) || null
    });
  }

  /**
   * Update core user profile fields
   */
  async updateUserProfile(userId: string, updateData: any): Promise<IUser | null> {
