export interface IUserRole extends Document {
  user_id: Types.ObjectId;
  role_id: Types.ObjectId;
  created_at: Date;
  updated_at: Date;
}

const UserRoleSchema = new Schema<IUserRole>(
  {
    user_id: {
      type: Schema.Types.ObjectId,
      ref: 'Users',
      required: [true, 'User ID là bắt buộc'],
      index: true,
    },
    role_id: {
      type: Schema.Types.ObjectId,
      ref: 'Roles',
      required: [true, 'Role ID là bắt buộc'],
    },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'userroles',
  },
);

// Compound unique index: one user can have one role per entry
UserRoleSchema.index({ user_id: 1, role_id: 1 }, { unique: true });

export const UserRoleModel = mongoose.models.UserRole || mongoose.model<IUserRole>('UserRole', UserRoleSchema, 'userroles');
